                const uint8_t* data,
                size_t dataSize,
                SecurePacketHeader& outHeader,
                std::vector<uint8_t>& outPayload,
                const Crypto::Identity* identity = nullptr);

            // Generate random nonce
            static uint32_t GenerateNonce();

            // XOR obfuscation (lightweight DPI resistance)
