            std::lock_guard<std::mutex> lock(m_mutex);
            for (auto& e : m_entries) {
                if (memcmp(e.node_id, node_id, DHT_NODE_ID_SIZE) == 0) {
                    e.last_seen = static_cast<uint32_t>(std::time(nullptr));
                    e.responsive = true;
                    break;
                }
            }
        }

        std::vector<KBucketEntry> KBucket::GetNodes() const {
            std::lock_guard<std::mutex> lock(m_mutex);
            return m_entries;
