                }
            }

            // Extract payload
            size_t payloadSize = outHeader.payload_size;
            if (payloadSize > finalPayloadSize) {
                return false;
            }

            outPayload.assign((const uint8_t*)finalPayload, (const uint8_t*)finalPayload + payloadSize);

