### 1. Updated `Protocol.hpp` (Hole Punch Packets)

```cpp
#pragma once
#include <cstdint>

namespace FreeAI {
    namespace Network {

        // Magic number (will be XORed with nonce for obfuscation)
        const uint32_t MAGIC_NUMBER = 0xF8EEA101;

        enum PacketType : uint8_t {
            PT_REGISTER = 1,
            PT_INTRO_REQUEST = 2,      // Ask Super Node for peer introduction
            PT_INTRO_RESPONSE = 3,     // Super Node sends peer IP:Port
            PT_PUNCH = 4,              // Hole punch attempt
            PT_PUNCH_ACK = 5,          // Hole punch successful
            PT_HANDSHAKE = 6,          // Direct P2P handshake (SIGNED)
            PT_PEER_LIST = 7,
            PT_INFERENCE_REQUEST = 8,
            PT_INFERENCE_RESPONSE = 9
        };

        // Packet flags
        const uint8_t FLAG_SIGNED = 0x01;
        const uint8_t FLAG_ENCRYPTED = 0x02;
        const uint8_t FLAG_COMPRESSED = 0x04;

        // Secure packet header (20 bytes base)
        struct SecurePacketHeader {
            uint32_t magic_xor;      // MAGIC_NUMBER XOR nonce (obfuscation)
            uint32_t nonce;          // Random value (prevents replay, used for XOR)
            uint8_t  flags;          // FLAG_SIGNED | FLAG_ENCRYPTED
            uint8_t  type;           // PacketType
            uint16_t payload_size;   // Actual payload size
            uint8_t  reserved[4];    // Alignment
        };

        // Hole Punch Payload (sent in PT_PUNCH)
        struct PunchPayload {
            char     sender_id[16];   // Short ID of sender
            uint64_t timestamp;       // For replay protection
            uint8_t  attempt_num;     // Punch attempt number (1-5)
            uint8_t  reserved[7];     // Alignment
        };

        const size_t SIGNATURE_SIZE = 88;   // Base64-encoded Ed25519 (64 bytes)
        const size_t CHACHA20_IV_SIZE = 12;
        const size_t MAX_PACKET_SIZE = 65535;

        // Hole punching constants
        const int MAX_PUNCH_ATTEMPTS = 5;
        const int PUNCH_INTERVAL_MS = 500;  // 500ms between attempts
        const int PUNCH_TIMEOUT_MS = 5000;  // Give up after 5 seconds

    }
}
```

