Excellent catch! These are classic C++ object lifecycle issues. The problem is that `DHTRoutingTable` doesn't have a **default constructor** or **copy assignment operator**, but `DHT` tries to use both.

Here are **two solutions** - choose the one that fits your coding style:

---

## Solution A: Fix `DHTRoutingTable` Constructors (Recommended)

### 1. Update `include/network/DHT.hpp`

Add default constructor and assignment operator to `DHTRoutingTable`:

```cpp
class DHTRoutingTable {
public:
    // NEW: Default constructor
    DHTRoutingTable();

    // Constructor with node ID
    DHTRoutingTable(const uint8_t* local_node_id);

    // NEW: Copy assignment operator
    DHTRoutingTable& operator=(const DHTRoutingTable& other);

    // NEW: Initialize with node ID (if using default constructor)
    void Initialize(const uint8_t* local_node_id);

    // ... rest of existing methods ...

private:
    uint8_t m_local_node_id[DHT_NODE_ID_SIZE];
    std::array<KBucket, 160> m_buckets;
    mutable std::mutex m_mutex;
    bool m_initialized;  // NEW: Track initialization state

    int GetBucketIndex(const uint8_t* node_id) const;
};
```

### 2. Update `src/network/DHT.cpp`

Implement the new constructors and operators:

```cpp
// DHTRoutingTable Implementation
DHTRoutingTable::DHTRoutingTable() : m_initialized(false) {
    memset(m_local_node_id, 0, DHT_NODE_ID_SIZE);
}

DHTRoutingTable::DHTRoutingTable(const uint8_t* local_node_id) : m_initialized(true) {
    memcpy(m_local_node_id, local_node_id, DHT_NODE_ID_SIZE);
}

DHTRoutingTable& DHTRoutingTable::operator=(const DHTRoutingTable& other) {
    if (this != &other) {
        std::lock_guard<std::mutex> lock(m_mutex);
        std::lock_guard<std::mutex> otherLock(other.m_mutex);
        memcpy(m_local_node_id, other.m_local_node_id, DHT_NODE_ID_SIZE);
        m_buckets = other.m_buckets;
        m_initialized = other.m_initialized;
    }
    return *this;
}

void DHTRoutingTable::Initialize(const uint8_t* local_node_id) {
    std::lock_guard<std::mutex> lock(m_mutex);
    memcpy(m_local_node_id, local_node_id, DHT_NODE_ID_SIZE);
    m_initialized = true;
}

int DHTRoutingTable::GetBucketIndex(const uint8_t* node_id) const {
    if (!m_initialized) return 0;  // Safety check
    for (int i = 0; i < 160; ++i) {
        int byte_idx = i / 8;
        int bit_idx = 7 - (i % 8);
        if (((m_local_node_id[byte_idx] ^ node_id[byte_idx]) >> bit_idx) & 1) {
            return i;
        }
    }
    return 159;
}

