Excellent catch! **Double-locking is a code smell** and can lead to deadlocks if lock ordering isn't consistent everywhere.

Here are **3 better approaches** to eliminate the nested locks:

---

## ✅ Solution 1: Copy Keys First (Recommended)

Check keys **outside** the seed mutex lock:

```cpp
void PeerManager::SeedRegistrationLoop() {
    FreeAI::Utils::SetThreadPriorityLow();

    while (m_running) {
        std::this_thread::sleep_for(std::chrono::milliseconds(1000));

        uint32_t curTs = static_cast<uint32_t>(std::time(nullptr));
        bool allRegistered = true;

        // Step 1: Collect unregistered seeds (minimal lock time)
        std::vector<size_t> unregisteredIndices;
        {
            std::lock_guard<std::mutex> lock(m_seedMutex);
            for (size_t i = 0; i < m_seedRegistrations.size(); ++i) {
                if (!m_seedRegistrations[i].registered) {
                    unregisteredIndices.push_back(i);
                    allRegistered = false;
                }
            }
        }  // ← m_seedMutex released here

        // Step 2: Check keys (separate lock, no nesting)
        std::unordered_map<size_t, bool> registrationStatus;
        {
            std::lock_guard<std::mutex> keyLock(m_keyMutex);
            for (size_t idx : unregisteredIndices) {
                const auto& reg = m_seedRegistrations[idx];
                // Check if we have this seed's public key
                bool hasSeedKey = false;
                for (const auto& kv : m_peerPublicKeys) {
                    // In production, match by IP:port
                    hasSeedKey = true;  // Simplified
                    break;
                }
                registrationStatus[idx] = hasSeedKey;
            }
        }  // ← m_keyMutex released here

        // Step 3: Update registration state (re-acquire seedMutex)
        for (size_t idx : unregisteredIndices) {
            bool hasSeedKey = registrationStatus[idx];

            std::lock_guard<std::mutex> lock(m_seedMutex);
            auto& reg = m_seedRegistrations[idx];

            if (hasSeedKey) {
                reg.registered = true;
                std::cout << "[PEER] Registration confirmed with " 
                          << reg.ip << ":" << reg.port << std::endl;
            } else {
                // Retry every 5 seconds if not registered
                if (curTs > reg.last_attempt_ts + 5 && reg.retry_count < 5) {
                    SendRegistration(reg);  // Note: This may need its own lock handling
                }
            }
        }

        // After all seeds registered, trigger DHT discovery (once)
        static bool dhtDiscoverySent = false;
        if (allRegistered && !dhtDiscoverySent) {
            dhtDiscoverySent = true;
            SendDHTDiscovery();
        }
    }
}
```

---

## ✅ Solution 2: Atomic Registration Flag (Simpler)

Use `std::atomic<bool>` for the registration flag (no mutex needed for reads):

```cpp
struct SeedRegistration {
    std::string ip;
    int port;
    std::string seed_address;
    uint32_t first_attempt_ts;
    uint32_t last_attempt_ts;
    std::atomic<bool> registered{false};  // ← Atomic, no mutex for reads
    std::atomic<int> retry_count{0};
};

void PeerManager::SeedRegistrationLoop() {
    FreeAI::Utils::SetThreadPriorityLow();

    while (m_running) {
        std::this_thread::sleep_for(std::chrono::milliseconds(1000));

        uint32_t curTs = static_cast<uint32_t>(std::time(nullptr));
        bool allRegistered = true;

        // Check registration status (no lock needed for atomic reads)
        std::vector<size_t> unregisteredIndices;
        for (size_t i = 0; i < m_seedRegistrations.size(); ++i) {
            if (!m_seedRegistrations[i].registered.load()) {
                unregisteredIndices.push_back(i);
                allRegistered = false;
            }
        }

        // Check keys (only m_keyMutex)
        for (size_t idx : unregisteredIndices) {
            const auto& reg = m_seedRegistrations[idx];
            bool hasSeedKey = false;

            {
                std::lock_guard<std::mutex> keyLock(m_keyMutex);
                for (const auto& kv : m_peerPublicKeys) {
                    hasSeedKey = true;
                    break;
                }
            }

            if (hasSeedKey) {
                m_seedRegistrations[idx].registered.store(true);
                std::cout << "[PEER] Registration confirmed with " 
                          << reg.ip << ":" << reg.port << std::endl;
            } else {
                int retries = reg.retry_count.load();
                if (curTs > reg.last_attempt_ts + 5 && retries < 5) {
                    SendRegistration(reg);
                    m_seedRegistrations[idx].retry_count.store(retries + 1);
                }
            }
        }

        // Trigger DHT discovery
        static bool dhtDiscoverySent = false;
        if (allRegistered && !dhtDiscoverySent) {
            dhtDiscoverySent = true;
            SendDHTDiscovery();
        }
    }
}
```

---

## ✅ Solution 3: Single Combined Mutex (Simplest)

If these are always accessed together, use **one mutex**:

```cpp
class PeerManager {
    // Replace two mutexes with one:
    mutable std::mutex m_networkMutex;  // ← Covers both seeds AND keys
    std::vector<SeedRegistration> m_seedRegistrations;
    std::unordered_map<std::string, std::string> m_peerPublicKeys;
    // ...
};

void PeerManager::SeedRegistrationLoop() {
    FreeAI::Utils::SetThreadPriorityLow();

    while (m_running) {
        std::this_thread::sleep_for(std::chrono::milliseconds(1000));

        uint32_t curTs = static_cast<uint32_t>(std::time(nullptr));
        bool allRegistered = true;

        // Single lock covers everything
        std::lock_guard<std::mutex> lock(m_networkMutex);

        for (auto& reg : m_seedRegistrations) {
            if (!reg.registered) {
                bool hasSeedKey = false;
                for (const auto& kv : m_peerPublicKeys) {
                    hasSeedKey = true;
                    break;
                }

                if (hasSeedKey) {
                    reg.registered = true;
                    std::cout << "[PEER] Registration confirmed with " 
                              << reg.ip << ":" << reg.port << std::endl;
                } else {
                    allRegistered = false;
                    if (curTs > reg.last_attempt_ts + 5 && reg.retry_count < 5) {
                        SendRegistration(reg);
                    }
                }
            }
        }

        if (allRegistered) {
            static bool dhtDiscoverySent = false;
            if (!dhtDiscoverySent) {
                dhtDiscoverySent = true;
                SendDHTDiscovery();
            }
        }
    }
}
```

---

## 📊 Comparison

| Solution | Pros | Cons | Best For |
| :--- | :--- | :--- | :--- |
| **1. Copy Keys First** | ✅ No nesting, fine-grained locks | ⚠️ More code, 3 lock cycles | High concurrency |
| **2. Atomic Flag** | ✅ No seedMutex for reads | ⚠️ Atomic overhead, still 2 locks | Medium concurrency |
| **3. Single Mutex** | ✅ Simplest, no nesting | ⚠️ Coarser locking (less parallelism) | Low-medium concurrency |

---

## 🎯 My Recommendation

**Use Solution 3 (Single Mutex)** for this project because:

1.  ✅ **Simplest** - Less code, easier to maintain
2.  ✅ **No deadlock risk** - Only one lock to manage
3.  ✅ **Performance is fine** - Registration loop runs once per second
4.  ✅ **Consistent** - `m_peerPublicKeys` and `m_seedRegistrations` are related data

The performance cost of a single mutex is **negligible** for a 1Hz background thread.

---

