        // XOR Distance Calculation
        uint64_t XORDistance(const uint8_t* id1, const uint8_t* id2) {
            uint64_t distance = 0;
            for (int i = 0; i < DHT_NODE_ID_SIZE; ++i) {
                distance |= (uint64_t)(id1[i] ^ id2[i]);
            }
            return distance;
