            std::lock_guard<std::mutex> lock(m_mutex);
            int bucket_idx = GetBucketIndex(node_id);
            
            KBucketEntry entry;
            memcpy(entry.node_id, node_id, DHT_NODE_ID_SIZE);
            entry.ip = ip;
