			std::vector<uint8_t> packet = PacketSecurity::PrepareOutgoing(
				type, payload, size, sign, encrypt, m_identity);

			if (packet.empty()) {
				std::cerr << "[PEER] Failed to prepare secure packet." << std::endl;
				return false;
